@namespace Lumeo

<div class="relative w-full overflow-auto">
    <table class="@CssClass" @attributes="AdditionalAttributes">
        @ChildContent
    </table>
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>
    /// When true, body rows alternate background (zebra striping) via a
    /// <c>tbody tr:nth-child(even)</c> rule so dense data tables are easier to
    /// scan. Applied with CSS variables only — no hardcoded colors.
    /// </summary>
    [Parameter] public bool Striped { get; set; }

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge(
        "w-full caption-bottom text-sm",
        Striped ? "[&_tbody_tr:nth-child(even)]:bg-muted/50" : null,
        Class);
}

@namespace Lumeo

<tbody class="@CssClass" @attributes="AdditionalAttributes">
