@namespace Lumeo

<td class="@CssClass" @attributes="AdditionalAttributes">
    @ChildContent
</td>

@code {
    [CascadingParameter] private Lumeo.Density? Density { get; set; }
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Cell padding tracks the ambient DensityScope so rows tighten in dense
    // data grids; Comfortable reproduces the historical `p-2`.
    private string PadClass => Density switch
    {
        Lumeo.Density.Compact => "px-2 py-1",
        Lumeo.Density.Spacious => "p-4",
        _ => "p-2"
    };

    private string CssClass => Cx.Merge(PadClass, "align-middle [&:has([role=checkbox])]:pr-0 [&>[role=checkbox]]:translate-y-[2px]", Class);
}

@namespace Lumeo
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@* Empty-state row for an otherwise-structured Table. Drop inside <TableBody>
   when the data set is empty so the table keeps its frame instead of
   collapsing to a bare header. Spans every column via colspan. *@
<tr @attributes="AdditionalAttributes">
    <td colspan="@SafeColumnCount" class="@CssClass">
        @if (ChildContent is not null)
        {
            @ChildContent
        }
        else
        {
            @(Text ?? L["Common.NoResults"])
        }
    </td>
</tr>

@code {
    /// <summary>Number of columns to span. Defaults to 1; set it to your column
    /// count so the empty message centers across the full table width.</summary>
    [Parameter] public int ColumnCount { get; set; } = 1;

    // Guard against a 0 / negative colspan — invalid HTML that can break the
    // table layout. Consumers occasionally bind ColumnCount to a not-yet-loaded
    // column collection (count 0).
    private int SafeColumnCount => ColumnCount < 1 ? 1 : ColumnCount;

    /// <summary>Optional plain-text message. Ignored when <see cref="ChildContent"/>
    /// is supplied. Falls back to the localized "No results" string.</summary>
    [Parameter] public string? Text { get; set; }

    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("h-24 p-4 text-center align-middle text-sm text-muted-foreground", Class);
}

@namespace Lumeo

<tfoot class="@CssClass" @attributes="AdditionalAttributes">
    @ChildContent
</tfoot>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Mirrors shadcn's TableFooter: a top border, muted fill and medium weight
    // for summary / totals rows, with the last row's bottom border removed so
    // it sits flush against the table edge.
    private string CssClass => Cx.Merge("border-t border-border/40 bg-muted/50 font-medium [&>tr]:last:border-b-0", Class);
}

@namespace Lumeo

